def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0
        for j in range(1, 20):
            if j % 4 == 0:
                factor = 1.3
            elif j % 3 == 0:
                factor = 1.1
            elif j % 2 == 0:
                factor = 0.95
            else:
                factor = 0.85
            term = factor * (1 / (j**2)) * (ratio ** j)
            if j % 5 == 0:
                term *= 1.05
            if j == 7 or j == 13:
                term *= 0.9
            score += term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3
        elif remaining < 0.07 * capacity:
            score *= 1.7
        elif remaining < 0.12 * capacity:
            score *= 1.2
        elif remaining < 0.25 * capacity:
            score *= 0.9
        else:
            score *= 0.8
        mod_conditions = [int(capacity) % m == 0 for m in (2,3,5,7,11)]
        if all(mod_conditions):
            score -= 0.2 * (capacity / 5)
        elif mod_conditions[1] and mod_conditions[2]:
            score -= 0.15 * (capacity / 9)
        elif mod_conditions[3] or mod_conditions[4]:
            score -= 0.1 * (capacity / 18)
        elif mod_conditions[0] or mod_conditions[2]:
            score -= 0.06 * (capacity / 25)
        else:
            score -= 0.04 * (capacity / 35)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            base_threshold = 0.01 * capacity * k
            if diff < base_threshold:
                penalty += 0.3 * k
            elif diff < 2 * base_threshold:
                penalty += 0.15 * k
            elif diff < 3 * base_threshold:
                penalty += 0.05 * k
            else:
                penalty -= 0.02 * k
            if k % 2 == 0 and diff < base_threshold:
                penalty += 0.1 * (k / 2)
        score += penalty
        if score < 0:
            score = 0
        if score > 2:
            for m in range(1, 6):
                base = capacity / m
                if abs(base - item) < 0.03 * base:
                    score *= (1 + 0.07 * m)
                elif abs(base - item) < 0.06 * base:
                    score *= (1 + 0.03 * m)
        elif score < 0.5:
            for q in range(1,4):
                if abs(item - capacity/(2*q)) < 0.02 * capacity:
                    score += 0.2 / q
        if capacity > 50 and ratio > 0.8:
            score *= 1.1
            for r in range(1,5):
                if abs(capacity - item*r*1.5) < 0.05*capacity:
                    score += 0.1 * r
        priorities[i] = score
    return priorities
